sql:
SELECT COUNT(endpoint_id) AS active_endpoint_count
FROM api_endpoints
WHERE is_active = 1;

SELECT COUNT(*) AS active_client_count
FROM client_applications
WHERE is_active = 1;

SELECT endpoint_name
FROM api_endpoints
WHERE is_active = 1;

SELECT COUNT(user_id) AS active_user_count
FROM user_accounts
WHERE is_active = 1;

SELECT COUNT(log_id) AS log_count
FROM api_usage_logs
WHERE request_type = 'GET' AND response_code = 200;

external_knowledge:
- 'usual number' refers to an average of more than 10 connections;
- 'recent past' indicates the last 30 days;
- 'active connections' refers to connections with a status of 'active'.

sql:
SELECT COUNT(*) AS active_connections_count
FROM connections
WHERE status = 'active';

SELECT endpoint_name
FROM api_endpoints
WHERE is_active = 1 AND endpoint_id = 1;

SELECT COUNT(log_id) AS successful_api_calls
FROM api_usage_logs
WHERE response_code = 200;
